import React, { useState, useEffect } from 'react';
import { Search, MapPin, Navigation, ChevronDown, Filter } from 'lucide-react';

const Home = () => {
  const [todasLasOfertas, setTodasLasOfertas] = useState([]);
  const [ofertasFiltradas, setOfertasFiltradas] = useState([]);
  const [busqueda, setBusqueda] = useState('');
  
  // ESTADOS DE UBICACIÓN
  const [provincia] = useState('Tucumán');
  const [ciudad] = useState('San Miguel de Tucumán');
  const [zona, setZona] = useState('Todas las zonas');

  const zonasTucuman = ['Todas las zonas', 'Barrio Norte', 'Barrio Sur', 'Yerba Buena', 'Tafí Viejo', 'Concepción'];

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acumulador = [];

    locales.forEach(local => {
      const ofertasLocal = JSON.parse(localStorage.getItem(`ofertas-local-${local.id}`) || "[]");
      acumulador = [...acumulador, ...ofertasLocal.map(o => ({
        ...o,
        nombreLocal: local.nombre,
        coords: local.coords,
        zona: local.zona || 'Barrio Norte' 
      }))];
    });

    setTodasLasOfertas(acumulador);
  }, []);

  useEffect(() => {
    let resultado = todasLasOfertas.filter(o => {
      const coincideBusqueda = o.producto.toLowerCase().includes(busqueda.toLowerCase());
      const coincideZona = zona === 'Todas las zonas' || o.zona === zona;
      return coincideBusqueda && coincideZona;
    });
    setOfertasFiltradas(resultado);
  }, [busqueda, zona, todasLasOfertas]);

  const irAlLocal = (coords) => {
    if (coords) {
      window.open(`https://www.openstreetmap.org/directions?engine=fossgis_osrm_car&route=%2C${coords[0]}%2C${coords[1]}`, '_blank');
    }
  };

  return (
    <div style={{ background: '#f1f5f9', minHeight: '100vh' }}>
      
      {/* HEADER DE UBICACIÓN DESLIZABLE */}
      <div style={locationHeader}>
        <div style={locationBar}>
          <div style={locationItem}>
            <span style={labelUbi}>Provincia</span>
            <div style={selectorUbi}>{provincia} <ChevronDown size={14} /></div>
          </div>
          <div style={dividerV} />
          <div style={locationItem}>
            <span style={labelUbi}>Ciudad</span>
            <div style={selectorUbi}>{ciudad} <ChevronDown size={14} /></div>
          </div>
        </div>

        {/* SELECTOR DE ZONAS (DESLIZABLE HORIZONTAL) */}
        <div style={zonaWrapper}>
          <div style={zonaScroll}>
            {zonasTucuman.map(z => (
              <button 
                key={z} 
                onClick={() => setZona(z)}
                style={zona === z ? zonaBtnActive : zonaBtn}
              >
                {z}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div style={{ padding: '20px 5%' }}>
        {/* BUSCADOR TIPO APLICACIÓN MÓVIL */}
        <div style={searchBox}>
          <Search size={20} color="#94a3b8" />
          <input 
            type="text" 
            placeholder="¿Qué producto buscas hoy?" 
            style={searchInput}
            onChange={(e) => setBusqueda(e.target.value)}
          />
          <Filter size={20} color="#e67e22" />
        </div>

        <h3 style={{ margin: '20px 0' }}>Ofertas en {zona}</h3>
        
        <div style={gridOfertas}>
          {ofertasFiltradas.length > 0 ? (
            ofertasFiltradas.map(o => (
              <div key={o.id} style={cardOferta}>
                <div style={imgPlaceholder}>
                   {o.imagen ? (
                     <img src={o.imagen} alt={o.producto} style={imgFull} />
                   ) : (
                     <MapPin size={30} color="#cbd5e1" />
                   )}
                   <div style={ahorroTag}>
                     -{Math.round(((o.precioViejo - o.precioNuevo)/o.precioViejo)*100)}%
                   </div>
                </div>
                <div style={{ padding: '12px' }}>
                  <h4 style={{ margin: '0 0 5px 0', fontSize: '1rem' }}>{o.producto}</h4>
                  <div style={{ display: 'flex', alignItems: 'baseline', gap: '5px' }}>
                    <span style={precioStyle}>${o.precioNuevo}</span>
                    <span style={precioAnt}>${o.precioViejo}</span>
                  </div>
                  <p style={localName}><MapPin size={12} /> {o.nombreLocal}</p>
                  
                  <button onClick={() => irAlLocal(o.coords)} style={btnIr}>
                    <Navigation size={14} /> Cómo llegar
                  </button>
                </div>
              </div>
            ))
          ) : (
            <div style={{ textAlign: 'center', gridColumn: '1/-1', padding: '50px' }}>
              <p style={{ color: '#64748b' }}>No hay ofertas en esta zona por el momento.</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

/* --- ESTILOS --- */
const locationHeader = { background: 'white', padding: '15px 5%', borderBottom: '1px solid #e2e8f0', position: 'sticky', top: 0, zIndex: 100 };
const locationBar = { display: 'flex', alignItems: 'center', background: '#f8fafc', borderRadius: '12px', padding: '10px 15px', marginBottom: '15px' };
const locationItem = { flex: 1, cursor: 'pointer' };
const labelUbi = { fontSize: '0.65rem', color: '#94a3b8', textTransform: 'uppercase', fontWeight: 'bold' };
const selectorUbi = { fontSize: '0.9rem', fontWeight: 'bold', display: 'flex', alignItems: 'center', gap: '5px' };
const dividerV = { width: '1px', height: '25px', background: '#e2e8f0', margin: '0 15px' };

const zonaWrapper = { overflow: 'hidden' };
const zonaScroll = { display: 'flex', gap: '10px', overflowX: 'auto', paddingBottom: '8px', scrollbarWidth: 'none' };
const zonaBtn = { padding: '8px 16px', borderRadius: '20px', border: '1px solid #e2e8f0', background: 'white', whiteSpace: 'nowrap', cursor: 'pointer', fontSize: '0.85rem', color: '#64748b' };
const zonaBtnActive = { ...zonaBtn, background: '#1e293b', color: 'white', borderColor: '#1e293b' };

const searchBox = { display: 'flex', alignItems: 'center', gap: '10px', background: 'white', padding: '12px 20px', borderRadius: '15px', border: '1px solid #e2e8f0', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' };
const searchInput = { border: 'none', outline: 'none', flex: 1, fontSize: '1rem' };

const gridOfertas = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', gap: '15px' };
const cardOferta = { background: 'white', borderRadius: '15px', overflow: 'hidden', border: '1px solid #e2e8f0', display: 'flex', flexDirection: 'column' };
const imgPlaceholder = { height: '120px', background: '#f8fafc', display: 'flex', justifyContent: 'center', alignItems: 'center', position: 'relative', overflow: 'hidden' };
const imgFull = { width: '100%', height: '100%', objectFit: 'cover' };
const ahorroTag = { position: 'absolute', top: '8px', right: '8px', background: '#ef4444', color: 'white', padding: '2px 6px', borderRadius: '5px', fontSize: '0.7rem', fontWeight: 'bold' };
const precioStyle = { margin: 0, fontWeight: '800', fontSize: '1.2rem', color: '#1e293b' };
const precioAnt = { fontSize: '0.8rem', textDecoration: 'line-through', color: '#94a3b8', marginLeft: '5px' };
const localName = { fontSize: '0.75rem', color: '#64748b', marginTop: '5px', display: 'flex', alignItems: 'center', gap: '4px' };
const btnIr = { marginTop: '10px', width: '100%', padding: '8px', borderRadius: '8px', border: 'none', background: '#f1f5f9', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '5px', fontSize: '0.8rem', fontWeight: 'bold' };

export default Home;
